import React, { useState, useEffect } from 'react';
import { useTable } from 'react-table';

const MaterialList = () => {
  const [materials, setMaterials] = useState([]);

  useEffect(() => {
    fetchMaterials();
  }, []);

  const fetchMaterials = async () => { await
    fetch('http://localhost:8081/')
      .then((response) => response.json())
      .then((data) => setMaterials(data))
      .catch((error) => console.log('Error:', error));
  };

  const columns = [
    { Header: 'Material ID', accessor: 'matid' },
    { Header: 'Name', accessor: 'name' },
    { Header: 'Description', accessor: 'description' },
    { Header: 'Unit of Measure', accessor: 'unit_of_measure' },
    { Header: 'Price per Unit', accessor: 'price_per_unit' },
    { Header: 'Recent Vendor', accessor: 'recent_vendor' },
  ];

  const tableInstance = useTable({ columns, data: materials });

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  return (
    <div>
      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps()}>{column.render('Header')}</th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

export default MaterialList;
